class Solution:
    def productExceptSelf(self, nums: List[int]) -> List[int]:
        length = len(nums)
        result = []
        prefix_products = [1]
        suffix_products = [1]

        prefix_product = 1
        suffix_product = 1

        for i in range(length - 1):
            # compute products from the beginning, i.e. for range 0 to i-1
            prefix_product *= nums[i]
            prefix_products.append(prefix_product)
            # compute products from the end, i.e. for range n to i+1
            suffix_product *= nums[-i - 1]
            suffix_products.append(suffix_product)

        for i in range(length):
            # compute product of 0 to i-1 and n to i+1
            result.append(prefix_products[i] * suffix_products[-i - 1])

        return result

solution = Solution()

for data in datas:
    result = solution.productExceptSelf(**data['Input'])
    print(f'{data['Input']=}')
    print(f'{result=}')
    test_result(result, data['Output'])
    print()

